@@ -68,5 +69,12 @@ func runDashboard(w io.Writer, errW io.Writer, session string) error {
 		projectDir = config.Default().GetProjectDir(session)
 	}

+	// Validate project directory exists, warn if not
+	if _, err := os.Stat(projectDir); os.IsNotExist(err) {
+		fmt.Fprintf(errW, "Warning: project directory does not exist: %s\n", projectDir)
+		fmt.Fprintf(errW, "Some features (beads, file tracking) may not work correctly.\n")
+		fmt.Fprintf(errW, "Check your projects_base setting in config: ntm config show\n\n")
+	}
+
 	return dashboard.Run(session, projectDir)
 }

@@ -21,12 +21,12 @@ import (
 func (m Model) fetchBeadsCmd() tea.Cmd {
 	return func() tea.Msg {
 		if !bv.IsInstalled() {
-			return BeadsUpdateMsg{Err: fmt.Errorf("bv not installed")}
+			// bv not installed - return unavailable summary (not an error)
+			return BeadsUpdateMsg{Summary: bv.BeadsSummary{Available: false, Reason: "bv not installed"}}
 		}
 		summary := bv.GetBeadsSummary(m.projectDir, 5) // Get top 5 ready/in-progress
-		if !summary.Available {
-			return BeadsUpdateMsg{Err: fmt.Errorf("%s", summary.Reason)}
-		}
+		// Return summary regardless of availability - let UI handle gracefully
+		// "No beads" is not an error, just an unavailable state
 		return BeadsUpdateMsg{Summary: *summary, Ready: summary.ReadyPreview}
 	}
 }

@@ -137,8 +137,19 @@ func (m *BeadsPanel) View() string {
 		if strings.TrimSpace(m.summary.Reason) == "" {
 			content.WriteString(components.LoadingState("Fetching beads pipeline…", w) + "\n")
 		} else {
-			reason := layout.TruncateRunes(m.summary.Reason, w-6, "…")
-			content.WriteString(components.ErrorState(reason, "Press r to refresh", w) + "\n")
+			// Check if this is a "no beads" case vs an actual error
+			reason := m.summary.Reason
+			isNotInitialized := strings.Contains(reason, "no .beads") ||
+				strings.Contains(reason, "bv not installed") ||
+				strings.Contains(reason, "bd not installed")
+			if isNotInitialized {
+				// Show subtle "not initialized" message instead of error
+				content.WriteString(components.EmptyState("Not initialized (run 'bd init')", w) + "\n")
+			} else {
+				// Actual error - show with refresh hint
+				truncReason := layout.TruncateRunes(reason, w-6, "…")
+				content.WriteString(components.ErrorState(truncReason, "Press r to refresh", w) + "\n")
+			}
 		}
 		return content.String()
 	}

